module RefModule (
    input clk,
    input rst,
    input signal_in,
    output reg zero_crossed
);

    reg unused_signal_prev;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            zero_crossed <= 0;
            unused_signal_prev <= 0;
        end else begin
            zero_crossed <= (signal_in && !unused_signal_prev) || (!signal_in && unused_signal_prev);
            unused_signal_prev <= signal_in;
        end
    end
endmodule
